/**
 * Generated by `createservice resident.FindOrganizationsByAddressService --type queries`
 */

const { featureToggleManager } = require('@open-condo/featureflags/featureToggleManager')
const { GQLCustomSchema, find } = require('@open-condo/keystone/schema')

const { DISABLE_DISCOVER_SERVICE_CONSUMERS } = require('@condo/domains/common/constants/featureflags')
const access = require('@condo/domains/resident/access/FindOrganizationsByAddressService')
const {
    MAX_RESIDENT_FIND_ORGANIZATIONS_BY_WINDOW_SEC,
    RESIDENT_FIND_ORGANIZATIONS_WINDOW_SEC,
} = require('@condo/domains/resident/constants/constants')
const {
    findBillingReceiptsForOrganizations,
    getOrganizationsWithAcquiring,
    getOrganizationsWithMeters,
    getBillingInformationForOrganizations,
    findMetersForOrganizations,
} = require('@condo/domains/resident/utils/serverSchema/findOrganizationsByAddress')
const { RESIDENT } = require('@condo/domains/user/constants/common')
const { RedisGuard } = require('@condo/domains/user/utils/serverSchema/guards')

const redisGuard = new RedisGuard()

const checkLimits = async (uniqueField) => {
    await redisGuard.checkCustomLimitCounters(
        `find-organizations-by-address-${uniqueField}`,
        RESIDENT_FIND_ORGANIZATIONS_WINDOW_SEC,
        MAX_RESIDENT_FIND_ORGANIZATIONS_BY_WINDOW_SEC,
    )
}

const FindOrganizationsByAddressService = new GQLCustomSchema('FindOrganizationsByAddressService', {
    types: [
        {
            access: true,
            type: 'input FindOrganizationsByAddressInput { addressKey: String!, unitName: String, unitType: String, tin: String, accountNumber: String }',
        },
        {
            access: true,
            type: 'type FindOrganizationByAddressOrganizationType { id: ID!, name: String!, tin: String!, type: OrganizationTypeType! }',
        },
        {
            access: true,
            type: 'type FindOrganizationByAddressReceiptType { number: String, category: ID!, balance: String, routingNumber: String, bankAccountNumber: String }',
        },
        {
            access: true,
            type: 'type FindOrganizationByAddressMeterType { resource: String!, number: String }',
        },
        {
            access: true,
            type: 'type FindOrganizationByAddressOutput { organization: FindOrganizationByAddressOrganizationType!, receipt: FindOrganizationByAddressReceiptType, meter: FindOrganizationByAddressMeterType }',
        },
    ],
    
    queries: [
        {
            access: access.canFindOrganizationsByAddress,
            schema: 'findOrganizationsByAddress (data: FindOrganizationsByAddressInput!): [FindOrganizationByAddressOutput]',
            resolver: async (parent, args, context) => {
                const { data } = args
                const { addressKey, unitName, unitType, tin, accountNumber } = data

                if (context.authedItem.type === RESIDENT) {
                    await checkLimits(context.authedItem.id)
                }

                const properties = await find('Property', { addressKey, deletedAt: null })

                if (!properties) {
                    return []
                }

                let organizations = await find('Organization', {
                    id_in: [...new Set(properties.map(({ organization }) => organization))],
                    ...tin ? { tin } : {},
                    deletedAt: null,
                })
                const organizationIds = organizations.map(({ id }) => id)
                const [withAcquiring, withMeters] = await Promise.all([
                    getOrganizationsWithAcquiring(organizationIds),
                    getOrganizationsWithMeters(organizationIds),
                ])

                organizations = organizations.filter(({ id }) => withAcquiring.has(id) || withMeters.has(id))

                const billingInformation = await getBillingInformationForOrganizations(organizations)

                organizations = organizations.filter(organization => billingInformation[organization.id])

                if (!organizations) {
                    return  []
                }

                organizations = await Promise.all(
                    organizations.map(async organization => {
                        const canRevealPersonalAccount = await featureToggleManager.isFeatureEnabled(
                            context,
                            DISABLE_DISCOVER_SERVICE_CONSUMERS,
                            { organization: organization.id }
                        )

                        return {
                            ...organization,
                            canRevealPersonalAccount,
                        }
                    })
                )

                const organizationIndex = Object.fromEntries(
                    organizations.map(({ id, name, tin, type }) =>
                        [ id, { organization: { id, name, tin, type }, receipt: null, meter: null } ]
                    )
                )

                if (!accountNumber && (!unitName || !unitType)) {
                    return Object.values(organizationIndex)
                }

                const receiptQuery = {
                    property: { addressKey, deletedAt: null },
                    ...(accountNumber
                        ? { number: accountNumber }
                        : { unitName, unitType }
                    ),
                }

                const meterQuery = accountNumber
                    ? { accountNumber }
                    : { unitName, unitType }
                
                let receipts = await findBillingReceiptsForOrganizations(organizations, billingInformation, receiptQuery)
                receipts = receipts.map(receipt1 =>
                    receipts.find(receipt2 =>
                        receipt1.category === receipt2.category &&
                        receipt1.number === receipt2.number
                    )
                )
                const meters = await findMetersForOrganizations(organizations, addressKey, meterQuery)
                const organizationsWithReceipts = new Set(receipts.map(({ organizationId }) => organizationId))
                const organizationsWithMeters = new Set(meters.map(({ organizationId }) => organizationId))
                const organizationsWithoutReceiptsAndMeters = accountNumber ? [] : Object
                    .values(organizationIndex)
                    .filter(({ organization: { id } }) => !organizationsWithReceipts.has(id) && !organizationsWithMeters.has(id))

                return [
                    ...organizationsWithoutReceiptsAndMeters,
                    ...meters.map(({ organizationId, meter }) => (
                        {
                            ...organizationIndex[organizationId],
                            meter,
                        }
                    )),
                    ...receipts.map(({ organizationId, ...receipt }) => (
                        {
                            ...organizationIndex[organizationId],
                            receipt,
                        }
                    )),
                ]
            },
        },
    ],

})

module.exports = {
    FindOrganizationsByAddressService,
}
